import type { JSX } from 'preact';

type IconProps = {
  size?: number;
  class?: string;
};

function Icon({ size = 18, d, viewBox = '0 0 24 24', fill, ...rest }: IconProps & { d: string; viewBox?: string; fill?: string }) {
  return (
    <svg width={size} height={size} viewBox={viewBox} fill={fill ?? '#000'} aria-hidden="true" {...rest}>
      <path d={d} />
    </svg>
  );
}

function MultiPathIcon({ size = 18, viewBox = '0 0 24 24', children, ...rest }: IconProps & { viewBox?: string; children: JSX.Element | JSX.Element[] }) {
  return (
    <svg width={size} height={size} viewBox={viewBox} aria-hidden="true" {...rest}>
      {children}
    </svg>
  );
}

/** Text-based fallback icon for services without a Simple Icons entry */
function TextIcon({ size = 18, label, bg }: IconProps & { label: string; bg: string }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" aria-hidden="true">
      <circle cx="12" cy="12" r="12" fill={bg} />
      <text x="12" y="16" text-anchor="middle" font-family="system-ui,sans-serif" font-weight="700" font-size="11" fill="#fff">{label}</text>
    </svg>
  );
}

